const raw = $input.first().json.body || $input.first().json;

// ────────────────────────────────────────────────
// v2 EXTENSION: Handle Prometheus Alertmanager format
// New alerts: LowDiskSpace, CriticalDiskSpace, PodNotScheduled
// Alertmanager sends { alerts: [ { status, labels, annotations, ... } ] }
// ────────────────────────────────────────────────
let alertData = null;
if (raw.alerts && Array.isArray(raw.alerts) && raw.alerts.length > 0) {
  const alert = raw.alerts[0];
  const alertname = alert.labels?.alertname || '';

  // Map Prometheus alert names to AutoFlow metric types
  const alertMetricMap = {
    'HighCPUUsage': { metric_type: 'cpu_usage', unit: '%' },
    'ContainerHighCPU': { metric_type: 'cpu_usage', unit: '%' },
    'NodeHighMemoryUsage': { metric_type: 'memory_usage', unit: '%' },
    'LowDiskSpace': { metric_type: 'disk_space_free_percent', unit: '%' },
    'CriticalDiskSpace': { metric_type: 'disk_space_free_percent', unit: '%' },
    'PodNotScheduled': { metric_type: 'pod_scheduling', unit: 'boolean' }
  };

  const mapped = alertMetricMap[alertname] || { metric_type: alertname.toLowerCase(), unit: '%' };

  // Extract metric value from annotations or labels
  let metricValue = 0;
  if (alertname === 'PodNotScheduled') {
    metricValue = 1; // Binary: 1 = scheduling failure detected
  } else if (alertname === 'LowDiskSpace' || alertname === 'CriticalDiskSpace') {
    // Value comes as ratio (0.0-1.0) from PromQL, convert to percent
    const rawVal = parseFloat(alert.annotations?.value || alert.labels?.value || 0);
    metricValue = rawVal < 1 ? Math.round(rawVal * 100 * 100) / 100 : rawVal;
  } else {
    metricValue = parseFloat(alert.annotations?.value || alert.labels?.value || 0);
  }

  alertData = {
    service_name: alert.labels?.service || alert.labels?.pod || alert.labels?.instance || 'kubernetes-node',
    namespace: alert.labels?.namespace || 'monitoring',
    pod_name: alert.labels?.pod || null,
    node_name: alert.labels?.instance || alert.labels?.node || null,
    metric_type: mapped.metric_type,
    metric_value: metricValue,
    metric_unit: mapped.unit,
    source: 'prometheus-alertmanager',
    environment: alert.labels?.environment || 'production',
    alert_name: alertname,
    alert_status: alert.status || 'firing',
    alert_severity: alert.labels?.severity || 'warning',
    alert_layer: alert.labels?.layer || 'application',
    mountpoint: alert.labels?.mountpoint || null,
    fstype: alert.labels?.fstype || null
  };
}

// Build the normalized event
const event = {
  event_id: `evt_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
  service_name: alertData?.service_name || raw.service_name || raw.labels?.job || 'unknown-service',
  namespace: alertData?.namespace || raw.namespace || raw.labels?.namespace || 'default',
  pod_name: alertData?.pod_name || raw.pod_name || raw.labels?.pod || null,
  node_name: alertData?.node_name || raw.node_name || raw.labels?.node || null,
  metric_type: alertData?.metric_type || raw.metric_type || raw.metric || 'cpu_usage',
  metric_value: alertData ? alertData.metric_value : parseFloat(raw.metric_value || raw.value || 0),
  metric_unit: alertData?.metric_unit || raw.unit || '%',
  source: alertData?.source || raw.source || 'prometheus',
  environment: alertData?.environment || raw.environment || 'production',
  timestamp: raw.timestamp || new Date().toISOString(),
  raw_payload: JSON.stringify(raw),
  // v2 extension fields
  alert_name: alertData?.alert_name || null,
  alert_severity: alertData?.alert_severity || null,
  alert_layer: alertData?.alert_layer || null,
  mountpoint: alertData?.mountpoint || null,
  fstype: alertData?.fstype || null
};

if (!event.service_name || event.metric_value === undefined) {
  throw new Error('Invalid telemetry: missing service_name or metric_value');
}

return { json: event };

const event = $('Normalize Telemetry').first().json;
const historicalData = $input.all().map(r => parseFloat(r.json.metric_value)).filter(v => !isNaN(v));

// ────────────────────────────────────────────────
// v2 EXTENSION: Added thresholds for new infrastructure alerts
//   disk_space_free_percent: < 10% = warning, < 5% = critical
//   pod_scheduling: any value of 1 = immediate anomaly (binary)
// ────────────────────────────────────────────────
const thresholds = { 
  cpu_usage: 85, 
  memory_usage: 90, 
  error_rate: 5, 
  latency_ms: 2000, 
  disk_usage: 95,
  disk_space_free_percent: 10,
  pod_scheduling: 0.5
};
const threshold = thresholds[event.metric_type] || 80;

// v2: PodNotScheduled is inherently an anomaly — binary detection
if (event.metric_type === 'pod_scheduling' && event.metric_value >= 1) {
  return { json: {
    ...event,
    is_anomaly: true,
    z_score: 99,
    baseline_mean: 0,
    baseline_stddev: 0,
    detection_method: 'binary_infrastructure_alert',
    anomaly_severity: 'critical',
    confidence: 0.95,
    historical_samples: 0,
    infrastructure_alert: true,
    alert_category: 'pod_scheduling_failure'
  }};
}

// v2: Disk space alerts — lower value = worse (inverted threshold)
if (event.metric_type === 'disk_space_free_percent') {
  const isCritical = event.metric_value < 5;
  const isLow = event.metric_value < 10;
  const isAnomaly = isLow;
  return { json: {
    ...event,
    is_anomaly: isAnomaly,
    z_score: isAnomaly ? (isCritical ? 5.0 : 3.0) : 0,
    baseline_mean: 50,
    baseline_stddev: 15,
    detection_method: 'threshold_infrastructure_alert',
    anomaly_severity: isCritical ? 'critical' : (isLow ? 'high' : 'none'),
    confidence: isCritical ? 0.95 : (isLow ? 0.80 : 0),
    historical_samples: 0,
    infrastructure_alert: true,
    alert_category: isCritical ? 'critical_disk_space' : 'low_disk_space'
  }};
}

let result;

if (historicalData.length >= 10) {
  const mean = historicalData.reduce((a, b) => a + b, 0) / historicalData.length;
  const variance = historicalData.reduce((sum, val) => sum + Math.pow(val - mean, 2), 0) / historicalData.length;
  const stddev = Math.sqrt(variance);
  const zScore = stddev > 0 ? (event.metric_value - mean) / stddev : 0;
  const recentMean = historicalData.slice(0, 5).reduce((a, b) => a + b, 0) / Math.min(5, historicalData.length);
  const spikeRatio = recentMean > 0 ? event.metric_value / recentMean : 1;
  const exceedsThreshold = event.metric_value > threshold;
  const isAnomaly = Math.abs(zScore) > 2.5 || exceedsThreshold || spikeRatio > 2.0;

  let severity = 'none', confidence = 0;
  if (isAnomaly) {
    if (Math.abs(zScore) > 4 || (exceedsThreshold && event.metric_value > threshold * 1.2)) { severity = 'critical'; confidence = 0.95; }
    else if (Math.abs(zScore) > 3 || exceedsThreshold) { severity = 'high'; confidence = 0.80; }
    else { severity = 'medium'; confidence = 0.65; }
  }

  result = { ...event, is_anomaly: isAnomaly, z_score: Math.round(zScore * 100) / 100, baseline_mean: Math.round(mean * 100) / 100, baseline_stddev: Math.round(stddev * 100) / 100, spike_ratio: Math.round(spikeRatio * 100) / 100, exceeds_threshold: exceedsThreshold, threshold_value: threshold, detection_method: 'zscore_threshold_spike', anomaly_severity: severity, confidence, historical_samples: historicalData.length };
} else {
  const exceedsThreshold = event.metric_value > threshold;
  result = { ...event, is_anomaly: exceedsThreshold, z_score: 0, baseline_mean: 0, baseline_stddev: 0, detection_method: 'threshold_only', anomaly_severity: exceedsThreshold ? 'medium' : 'none', confidence: exceedsThreshold ? 0.5 : 0, historical_samples: historicalData.length };
}

return { json: result };

const event = $('Receive Anomaly Event').first().json;
const allInputs = $input.all();

// Parse agent responses - try both compact and spaced JSON key formats
const parseAgent = (inputs, agentName, fallbackIndex) => {
  try {
    const agentData = inputs.find(item => {
      const content = item.json?.choices?.[0]?.message?.content;
      if (!content) return false;
      return content.includes(`"agent":"${agentName}"`) || 
             content.includes(`"agent": "${agentName}"`);
    });

    // Fallback: use positional index (0=anomaly,1=risk,2=sla,3=context)
    const source = agentData || (inputs[fallbackIndex]?.json?.choices ? inputs[fallbackIndex] : null);
    if (!source) return { score: 0.5, reasoning: 'Agent not found', confidence: 0.5, recommended_action: 'alert' };

    const text = source.json.choices[0].message.content;
    const cleaned = text.replace(/```json|```/g, '').trim();
    const parsed = JSON.parse(cleaned);
    return {
      score: typeof parsed.score === 'number' ? parsed.score : 0.5,
      reasoning: parsed.reasoning || 'No reasoning provided',
      recommended_action: parsed.recommended_action || 'alert',
      confidence: typeof parsed.confidence === 'number' ? parsed.confidence : 0.5,
      ...parsed
    };
  } catch (e) {
    return { score: 0.5, reasoning: 'Parse error: ' + e.message, confidence: 0.5, recommended_action: 'alert' };
  }
};

const agents = {
  anomaly: parseAgent(allInputs, 'anomaly', 0),
  risk: parseAgent(allInputs, 'risk', 1),
  sla: parseAgent(allInputs, 'sla', 2),
  context: parseAgent(allInputs, 'context', 3)
};

// Weights come from DB rows (items without .choices)
const weightsData = allInputs.filter(item => item.json.agent_name !== undefined);
const weights = {};
weightsData.forEach(row => {
  weights[row.json.agent_name] = parseFloat(row.json.current_weight);
});

const defaultWeights = { anomaly: 0.30, risk: 0.35, sla: 0.25, context: 0.10 };
const w = { ...defaultWeights, ...weights };

// Clamp scores to [0,1]
const clamp = v => Math.max(0, Math.min(1, v));
const consensus_score = 
  (clamp(agents.anomaly.score) * w.anomaly) +
  (clamp(agents.risk.score) * w.risk) +
  (clamp(agents.sla.score) * w.sla) +
  (clamp(agents.context.score) * w.context);

let decision, remediation_action;
if (consensus_score < 0.3) {
  decision = 'ignore';
  remediation_action = null;
} else if (consensus_score < 0.6) {
  decision = 'alert';
  remediation_action = null;
} else {
  decision = 'remediate';

  // ────────────────────────────────────────────────
  // v2 EXTENSION: Infrastructure-aware action selection
  // Map new K8s v2 alert categories to appropriate remediation actions
  // ────────────────────────────────────────────────
  const alertCategory = event.alert_category || null;
  const metricType = event.metric_type;

  if (alertCategory === 'pod_scheduling_failure' || metricType === 'pod_scheduling') {
    remediation_action = 'reschedule_pod';
  } else if (alertCategory === 'critical_disk_space' || alertCategory === 'low_disk_space' || metricType === 'disk_space_free_percent') {
    remediation_action = 'cleanup_disk';
  } else {
    const actions = [
      agents.anomaly.recommended_action, 
      agents.risk.recommended_action, 
      agents.sla.recommended_action,
      agents.context.recommended_action
    ];
    remediation_action = actions.find(a => ['restart_pod', 'scale_service', 'reroute_traffic', 'drain_node', 'cleanup_disk', 'reschedule_pod'].includes(a)) || 'restart_pod';
  }
}

return {
  json: {
    decision_id: `dec_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    event_id: event.event_id,
    service_name: event.service_name,
    namespace: event.namespace,
    metric_type: event.metric_type,
    metric_value: event.metric_value,
    consensus_score: Math.round(consensus_score * 10000) / 10000,
    decision,
    remediation_action,
    agents,
    weights_used: w,
    decided_at: new Date().toISOString(),
    // v2: pass infrastructure context downstream
    alert_name: event.alert_name || null,
    alert_category: event.alert_category || null,
    alert_layer: event.alert_layer || null,
    infrastructure_alert: event.infrastructure_alert || false,
    mountpoint: event.mountpoint || null,
    node_name: event.node_name || null
  }
};

const d = $input.first().json;
const escape = v => (v === null || v === undefined) ? null : String(v).replace(/'/g, "''");
return {
  json: {
    ...d,
    safe_raw_payload: escape(d.raw_payload)
  }
};

const d = $input.first().json;
const escape = v => (v === null || v === undefined) ? '' : String(v).replace(/'/g, "''");
return {
  json: {
    ...d,
    safe_anomaly_reasoning: escape(d.agents?.anomaly?.reasoning),
    safe_risk_reasoning: escape(d.agents?.risk?.reasoning),
    safe_sla_reasoning: escape(d.agents?.sla?.reasoning),
    safe_context_reasoning: escape(d.agents?.context?.reasoning),
    safe_weights_used: escape(JSON.stringify(d.weights_used))
  }
};
